// These two JSX forms are exactly equivalent:
<Button>Save</Button>
<Button children="Save" />

// React transforms both to:
React.createElement(Button, { children: 'Save' })

// Destructuring — idiomatic
function Card({ title, children }) {
  return (
    <section className="card">
      <header>{title}</header>
      <div className="card-body">{children}</div>
    </section>
  );
}

// Usage — children is anything nested inside the tags:
<Card title="User Profile">
  <Avatar src={user.photo} />
  <h2>{user.name}</h2>
  <p>{user.bio}</p>
</Card>

// Modal doesn't know or import anything about its content.
// Different callers can put completely different content inside it.
function Modal({ title, onClose, children }) {
  return (
    <div className="modal-overlay">
      <div className="modal" role="dialog" aria-labelledby="modal-title">
        <div className="modal-header">
          <h2 id="modal-title">{title}</h2>
          <button onClick={onClose} aria-label="Close">✕</button>
        </div>
        <div className="modal-body">{children}</div>
      </div>
    </div>
  );
}

// Caller 1 — confirmation dialog
<Modal title="Delete account?" onClose={closeModal}>
  <p>This action cannot be undone. Are you sure?</p>
  <div className="button-row">
    <Button onClick={closeModal}>Cancel</Button>
    <Button variant="danger" onClick={deleteAccount}>Delete</Button>
  </div>
</Modal>

// Caller 2 — image gallery
<Modal title="Photos" onClose={closeModal}>
  <ImageGallery images={photos} />
</Modal>

// Named props for multiple slots — common in layout components
function PageShell({ header, sidebar, children, footer }) {
  return (
    <div className="page">
      <header>{header}</header>
      <div className="layout">
        <aside>{sidebar}</aside>
        <main>{children}</main>   {/* primary slot is still children */}
      </div>
      <footer>{footer}</footer>
    </div>
  );
}

<PageShell
  header={<Navbar />}
  sidebar={<FilterPanel />}
  footer={<Footer />}
>
  <ProductGrid items={products} />
</PageShell>

// Guard: only render children if they exist
function OptionalSection({ title, children }) {
  if (!children) return null;  // nothing to render
  return (
    <section>
      <h3>{title}</h3>
      {children}
    </section>
  );
}

// Conditional: show children based on a flag
function Collapsible({ isOpen = true, children }) {
  return isOpen ? <div className="collapsible">{children}</div> : null;
}

// Wrapping: add context around children
function ScrollBox({ maxHeight = 300, children }) {
  return (
    <div style={{ maxHeight, overflowY: 'auto' }}>
      {children}
    </div>
  );
}

import { Children, cloneElement, isValidElement } from 'react';

// Count children regardless of type:
function TabList({ children }) {
  const count = Children.count(children);
  return (
    <div role="tablist" aria-label={`${count} tabs`}>
      {children}
    </div>
  );
}

// Map over children, injecting a prop into each:
function RadioGroup({ name, children }) {
  return (
    <fieldset>
      {Children.map(children, (child, index) =>
        isValidElement(child)
          ? cloneElement(child, { name, id: `${name}-${index}` })
          : child
      )}
    </fieldset>
  );
}

// Convert to a stable array for indexing:
function Wizard({ children, step }) {
  const steps = Children.toArray(children);
  return <div>{steps[step]}</div>;
}

import { ReactNode, PropsWithChildren } from 'react';

// Manual annotation:
type CardProps = {
  title: string;
  children?: ReactNode;   // optional: component can render without children
};

function Card({ title, children }: CardProps) {
  return (
    <section>
      <h2>{title}</h2>
      {children}
    </section>
  );
}

// Shorthand with PropsWithChildren — auto-adds children?: ReactNode:
type CardProps = PropsWithChildren<{ title: string }>;

function Card({ title, children }: CardProps) {
  return (
    <section>
      <h2>{title}</h2>
      {children}
    </section>
  );
}

// DataFetcher handles loading / error states;
// the caller decides what to do with the data
function DataFetcher({ url, children }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch(url)
      .then(r => r.json())
      .then(setData)
      .catch(setError)
      .finally(() => setLoading(false));
  }, [url]);

  // children is a function — call it with the resolved state:
  return children({ data, loading, error });
}

// Usage:
<DataFetcher url="/api/users">
  {({ data, loading, error }) => {
    if (loading) return <Spinner />;
    if (error)   return <ErrorMessage error={error} />;
    return <UserList users={data} />;
  }}
</DataFetcher>

// 1. Provider pattern — wraps the app to inject context
function ThemeProvider({ theme, children }) {
  return (
    <ThemeContext.Provider value={theme}>
      {children}
    </ThemeContext.Provider>
  );
}

// 2. Error boundary — wraps a subtree to catch errors
class ErrorBoundary extends React.Component {
  state = { hasError: false };
  static getDerivedStateFromError() { return { hasError: true }; }
  render() {
    if (this.state.hasError) return <this.props.fallback />;
    return this.props.children;    // normal path: render children unchanged
  }
}

// 3. Suspense — shows a fallback while children load
<Suspense fallback={<PageSkeleton />}>
  <HeavyPage />    {/* children prop of Suspense */}
</Suspense>

// 4. Fragment — groups children with no extra DOM node
<>
  <Header />
  <Main />
  <Footer />
</>

const UserContext = React.createContext(null);

// Provider uses children to wrap the subtree
function UserProvider({ user, children }) {
  return (
    <UserContext.Provider value={user}>
      {children}    {/* all descendants can read UserContext */}
    </UserContext.Provider>
  );
}

// Anywhere inside UserProvider's children:
function Avatar() {
  const user = React.useContext(UserContext);
  return <img src={user.photo} alt={user.name} />;
}

// App wires them together
function App() {
  const [user] = useState(fetchUser());
  return (
    <UserProvider user={user}>
      <Navbar />           {/* contains Avatar somewhere inside */}
      <Main />
    </UserProvider>
  );
}

// Conceptual Slot: forwards its own props onto its single child
import { cloneElement, isValidElement } from 'react';

function Slot({ children, ...slotProps }) {
  if (!isValidElement(children)) return children;
  // Merge slotProps into the child's existing props:
  return cloneElement(children, {
    ...slotProps,
    ...children.props,  // child's own props win for conflicts
  });
}

// Tooltip uses Slot to add aria attrs to whatever the user passes:
function Tooltip({ id, children }) {
  return (
    <>
      <Slot aria-describedby={id} onMouseEnter={show} onMouseLeave={hide}>
        {children}     {/* the user's actual trigger element */}
      </Slot>
      <div id={id} role="tooltip">{tooltipContent}</div>
    </>
  );
}

// The user passes their own element — no extra wrapper in the DOM:
<Tooltip id="t1">
  <button>Hover me</button>   {/* receives aria-describedby etc. */}
</Tooltip>

// Example: counter state lives in App; Card is a dumb wrapper
function App() {
  const [count, setCount] = useState(0);
  return (
    <Card title="Counter">
      {/* HeavyList does NOT receive count — it will not re-render */}
      <HeavyList items={staticItems} />
      <button onClick={() => setCount(c => c + 1)}>+{count}</button>
    </Card>
  );
}

const Card = React.memo(function Card({ title, children }) {
  return <section><h2>{title}</h2><div>{children}</div></section>;
});

// When count changes:
// - App re-renders
// - New <Card> element is created (new children object)
// - Card.memo sees children changed (new reference) and re-renders Card
// - But HeavyList's own props haven't changed, so React bails out there
